     5→//! VVC Machine Commit - programmatic commit infrastructure
     6→//!
     7→//! For automated operations that know exactly what files to commit
     8→//! and don't need Claude assistance. Contrast with vvcc_commit which
     9→//! is designed for interactive sessions with Claude message generation.
    10→//!
    11→//! Use cases:
    12→//!   - JJK retire: trophy file + paddock + gallops update
    13→//!   - VOK install: kit files being installed
    14→//!   - CMK normalize: normalized concept model files
    15→//!   - Any automated operation with predictable file sets
    16→//!
    17→//! Exit codes (when using vvcm_run):
    18→//!   0 - Success (commit hash printed to stdout)
    19→//!   1 - Failure (staging failed, guard failed, commit failed)
    20→
    21→use std::process::Command;
    22→
    23→use crate::vvcc_commit::vvcc_CommitLock;
    24→use crate::vvcg_guard;
    25→
    26→/// Arguments for machine commit operation
    27→#[derive(Debug, Clone)]
    28→pub struct vvcm_CommitArgs {
    29→    /// Explicit files to stage (required, non-empty)
    30→    pub files: Vec<String>,
    31→    /// Commit message (required)
    32→    pub message: String,
    33→    /// Size limit in bytes for guard check
    34→    pub size_limit: u64,
    35→    /// Warning threshold in bytes for guard check
    36→    pub warn_limit: u64,
    37→}
    38→
    39→/// Machine commit for programmatic operations.
    40→///
    41→/// Unlike vvcc_commit, this:
    42→/// - Stages only specified files (not git add -A)
    43→/// - Requires explicit message (no Claude generation)
    44→/// - Does not add Co-Authored-By trailer
    45→/// - Uses caller-specified guard limits
    46→///
    47→/// The `_lock` parameter serves as compile-time proof that the caller
    48→/// holds the commit lock. The lock is not consumed; caller retains it.
    49→///
    50→/// Returns the commit hash on success.
    51→pub fn vvcm_commit(
    52→    _lock: &vvcc_CommitLock,
    53→    args: &vvcm_CommitArgs,
    54→) -> Result<String, String> {
    55→    // Validate args
    56→    if args.files.is_empty() {
    57→        return Err("files list must not be empty".to_string());
    58→    }
    59→    if args.message.is_empty() {
    60→        return Err("message must not be empty".to_string());
    61→    }
    62→
    63→    // Stage explicit files
    64→    zvvcm_stage_files(&args.files)?;
    65→
    66→    // Run guard with custom limits
    67→    let guard_args = vvcg_guard::vvcg_GuardArgs {
    68→        limit: args.size_limit,
    69→        warn: args.warn_limit,
    70→    };
    71→    let guard_result = vvcg_guard::vvcg_run(&guard_args, None);
    72→    match guard_result {
    73→        0 => {}
    74→        1 => return Err("Staged content exceeds size limit".to_string()),
    75→        2 => {
    76→            eprintln!("vvcm_commit: WARNING - staged content near size limit");
    77→        }
    78→        _ => return Err(format!("Guard returned unexpected code: {}", guard_result)),
    79→    }
    80→
    81→    // Commit with message (no Co-Authored-By)
    82→    zvvcm_execute_commit(&args.message)
    83→}
    84→
    85→/// Stage specific files using git add
    86→fn zvvcm_stage_files(files: &[String]) -> Result<(), String> {
    87→    let mut cmd = Command::new("git");
    88→    cmd.arg("add").arg("--");
    89→    for file in files {
    90→        cmd.arg(file);
    91→    }
    92→
    93→    let result = cmd
    94→        .output()
    95→        .map_err(|e| format!("Failed to run git add: {}", e))?;
    96→
    97→    if result.status.success() {
    98→        eprintln!("vvcm_commit: staged {} file(s)", files.len());
    99→        Ok(())
   100→    } else {
   101→        Err(format!(
   102→            "git add failed: {}",
   103→            String::from_utf8_lossy(&result.stderr)
   104→        ))
   105→    }
   106→}
   107→
   108→/// Execute git commit with message (no Co-Authored-By)
   109→fn zvvcm_execute_commit(message: &str) -> Result<String, String> {
   110→    let output = Command::new("git")
   111→        .args(["commit", "-m", message])
   112→        .output()
   113→        .map_err(|e| format!("Failed to run git commit: {}", e))?;
   114→
   115→    if !output.status.success() {
   116→        let stderr = String::from_utf8_lossy(&output.stderr);
   117→        return Err(format!("git commit failed: {}", stderr));
   118→    }
   119→
   120→    // Get commit hash
   121→    let hash_output = Command::new("git")
   122→        .args(["rev-parse", "HEAD"])
   123→        .output()
   124→        .map_err(|e| format!("Failed to get commit hash: {}", e))?;
   125→
   126→    if !hash_output.status.success() {
   127→        return Err("Failed to retrieve commit hash".to_string());
   128→    }
   129→
   130→    let hash = String::from_utf8_lossy(&hash_output.stdout)
   131→        .trim()
   132→        .to_string();
   133→
   134→    eprintln!("vvcm_commit: committed {}", &hash[..8.min(hash.len())]);
   135→    Ok(hash)
   136→}
