     4→//! Favor encoding - Firemark and Coronet identity types
     5→//!
     6→//! Implements base64 encoding/decoding for Job Jockey identity types:
     7→//! - Firemark: Heat identity (2 base64 chars, 0-4095)
     8→//! - Coronet: Pace identity (5 base64 chars, globally unique)
     9→
    10→use serde::{Deserialize, Serialize};
    11→
    12→/// URL-safe base64 charset (RFC 4648 section 5)
    13→pub const JJRF_CHARSET: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_";
    14→
    15→/// Firemark prefix character
    16→pub const JJRF_FIREMARK_PREFIX: char = '₣';
    17→
    18→/// Coronet prefix character
    19→pub const JJRF_CORONET_PREFIX: char = '₢';
    20→
    21→/// Maximum value for Firemark (2^12 - 1)
    22→pub const JJRF_FIREMARK_MAX: u16 = 4095;
    23→
    24→/// Maximum value for Coronet pace index (2^18 - 1)
    25→pub const JJRF_CORONET_PACE_MAX: u32 = 262143;
    26→
    27→/// Look up the position of a character in the charset
    28→pub fn zjjrf_char_to_value(c: char) -> Result<u8, String> {
    29→    let byte = c as u8;
    30→    JJRF_CHARSET
    31→        .iter()
    32→        .position(|&b| b == byte)
    33→        .map(|pos| pos as u8)
    34→        .ok_or_else(|| format!("Invalid base64 character: '{}'", c))
    35→}
    36→
    37→/// Get the character at a given position in the charset
    38→pub fn zjjrf_value_to_char(value: u8) -> char {
    39→    JJRF_CHARSET[value as usize] as char
    40→}
    41→
    42→/// Heat identity - 2 base64 characters encoding 0-4095
    43→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
    44→pub struct jjrf_Firemark(pub String);
    45→
    46→/// Pace identity - 5 base64 characters, globally unique
    47→/// First 2 chars encode parent Heat, last 3 encode pace index (0-262143)
    48→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
    49→pub struct jjrf_Coronet(pub String);
    50→
    51→impl jjrf_Firemark {
    52→    /// Encode an integer (0-4095) as a Firemark
    53→    pub fn jjrf_encode(value: u16) -> Self {
    54→        debug_assert!(value <= JJRF_FIREMARK_MAX, "Firemark value {} exceeds max {}", value, JJRF_FIREMARK_MAX);
    55→        let high = zjjrf_value_to_char((value / 64) as u8);
    56→        let low = zjjrf_value_to_char((value % 64) as u8);
    57→        jjrf_Firemark(format!("{}{}", high, low))
    58→    }
    59→
    60→    /// Decode a Firemark to its integer value
    61→    pub fn jjrf_decode(&self) -> Result<u16, String> {
    62→        let chars: Vec<char> = self.0.chars().collect();
    63→        if chars.len() != 2 {
    64→            return Err(format!("Firemark must be 2 characters, got {}", chars.len()));
    65→        }
    66→        let high = zjjrf_char_to_value(chars[0])? as u16;
    67→        let low = zjjrf_char_to_value(chars[1])? as u16;
    68→        Ok(high * 64 + low)
    69→    }
    70→
    71→    /// Parse a Firemark from string input (with or without prefix)
    72→    pub fn jjrf_parse(input: &str) -> Result<Self, String> {
    73→        let stripped = input.strip_prefix(JJRF_FIREMARK_PREFIX).unwrap_or(input);
    74→        if stripped.len() != 2 {
    75→            return Err(format!(
    76→                "Firemark must be 2 base64 characters (with or without {} prefix), got '{}'",
    77→                JJRF_FIREMARK_PREFIX, input
    78→            ));
    79→        }
    80→        // Validate all characters are in charset
    81→        for c in stripped.chars() {
    82→            zjjrf_char_to_value(c)?;
    83→        }
    84→        Ok(jjrf_Firemark(stripped.to_string()))
    85→    }
    86→
    87→    /// Get the raw base64 string (without prefix)
    88→    pub fn jjrf_as_str(&self) -> &str {
    89→        &self.0
    90→    }
    91→
    92→    /// Format with prefix for display
    93→    pub fn jjrf_display(&self) -> String {
    94→        format!("{}{}", JJRF_FIREMARK_PREFIX, self.0)
    95→    }
    96→}
